-- ---------------------------------------------------------------------------
-- 002_seed_default_list.sql  (generated by scripts/generate-default-list-sql.mjs)
--
-- Seeds the SF Chronicle Top 100 as a real lists row owned by kidhack so
-- the rest of the app can treat it like any other custom list. Idempotent:
-- safe to re-run after editing data/restaurants.js (regenerate this file
-- by running the script).
--
-- Prerequisite: kidhack@kidhack.com must have signed in at least once so the
-- corresponding auth.users row exists. The DO block raises if it doesn't.
-- ---------------------------------------------------------------------------

do $$
declare
  owner       uuid;
  new_list_id uuid;
begin
  select id into owner from auth.users where email = 'kidhack@kidhack.com';
  if owner is null then
    raise exception
      'kidhack@kidhack.com has not signed in yet -- have them sign in, then rerun this migration';
  end if;

  values (owner, 'kidhack')
  on conflict (user_id) do nothing;

  values (owner, 'chronicle-top-100-2026', 'SF Chronicle Top 100 - 2026')
  on conflict (slug) do update set
    name       = excluded.name,
    updated_at = now()
  returning id into new_list_id;

  on conflict (list_id, rank) do update set
    name    = excluded.name,
    address = excluded.address,
    city    = excluded.city,
    cuisine = excluded.cuisine,
    url     = excluded.url,
    lat     = excluded.lat,
    lng     = excluded.lng;
end $$;
